function loadSave() {
  // Try current key first
  let raw = localStorage.getItem('wonml_save_v1');
  if (raw) {
    const save = JSON.parse(raw);
    if (save.schema_version === CURRENT_SAVE_VERSION) return save;
    return migrateInPlace(save);
  }
  // Check for legacy fragmented keys
  if (localStorage.getItem('wonml_r2_best') !== null) {
    return migrateFromR2();
  }
  // Fresh install
  return createDefaultSave();
}

function migrateInPlace(save) {
  // Apply incremental upgrades
  if (save.schema_version < 2) upgradeV1ToV2(save);
  // Add future versions here
  return save;
}
